const fs = require('fs');
const _ = require('lodash');

const glob = require('glob');

const minify = require('html-minifier').minify;

/**
 * html 파일들을 압축한다.
 */
class HtmlMinifierPlugin{

    constructor({
    } = {}){}
    apply(compiler){

        compiler.plugin('done', function(){

            const outputPath = this.outputPath;

            const files = glob.sync(`${outputPath}/**/*.html`);

            _.forEach(files, v => {

                const source = fs.readFileSync(v, 'utf-8');
                const output = minify(source, {
                    collapseWhitespace: true,
                    minifyJS: true,
                    minifyCSS: true,
                    removeComments: true
                });

                fs.writeFileSync(v, output);
            });
        });
    };
}

module.exports = HtmlMinifierPlugin;